content:
/* ============================================================
   SOUTH POINT VILLAS — Main Stylesheet
   Palette: Ocean Deep / Warm Sand / Terracotta / Tropical
   Fonts: Cormorant Garamond + DM Sans
   ============================================================ */

*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

:root {
  --ocean:    #1B3D4F;
  --sand:     #F2EDE6;
  --terra:    #C87941;
  --tropical: #3D7A63;
  --cream:    #FFFDF8;
  --ink:      #2A1F1A;
  --muted:    #7a7068;
  --divider:  #ddd8d0;
  --shadow:   rgba(43,31,26,0.08);
  --shadow-lg:rgba(43,31,26,0.16);

  --font-serif: 'Cormorant Garamond', Georgia, serif;
  --font-sans:  'DM Sans', system-ui, sans-serif;

  --nav-h: 72px;
  --radius: 12px;
  --radius-lg: 20px;
}

html { scroll-behavior: smooth; font-size: 16px; }

body {
  font-family: var(--font-sans);
  background: var(--cream);
  color: var(--ink);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

img { display: block; max-width: 100%; height: auto; }
a { color: inherit; text-decoration: none; }
button { cursor: pointer; border: none; background: none; font: inherit; }

/* ── TYPOGRAPHY ── */
h1, h2, h3 { font-family: var(--font-serif); font-weight: 400; line-height: 1.1; }

h1 { font-size: clamp(2.8rem, 6vw, 5rem); letter-spacing: -0.02em; }
h2 { font-size: clamp(2rem, 4vw, 3.2rem); letter-spacing: -0.015em; }
h3 { font-size: clamp(1.4rem, 2.5vw, 1.9rem); letter-spacing: -0.01em; }
h4 { font-family: var(--font-sans); font-size: 0.72rem; font-weight: 500; letter-spacing: 0.15em; text-transform: uppercase; }

p { font-size: 0.95rem; line-height: 1.8; color: var(--muted); }
p + p { margin-top: 0.75rem; }

em { font-style: italic; color: var(--terra); }
strong { font-weight: 600; color: var(--ink); }

/* ── LAYOUT ── */
.container { max-width: 1180px; margin: 0 auto; padding: 0 2rem; }
.container--narrow { max-width: 760px; margin: 0 auto; padding: 0 2rem; }

section { padding: 6rem 0; }
section.dark { background: var(--ocean); color: var(--cream); }
section.dark p { color: rgba(255,255,255,0.7); }
section.dark h2, section.dark h3, section.dark h4 { color: var(--cream); }
section.sand { background: var(--sand); }

.section-label {
  font-family: var(--font-sans);
  font-size: 0.65rem;
  font-weight: 500;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--terra);
  margin-bottom: 1rem;
  display: block;
}

.section-label.light { color: var(--accent-light, #e8a48e); }

/* ── NAVIGATION ── */
.nav {
  position: fixed;
  top: 0; left: 0; right: 0;
  height: var(--nav-h);
  z-index: 1000;
  display: flex;
  align-items: center;
  padding: 0 2rem;
  transition: background 0.4s, backdrop-filter 0.4s, box-shadow 0.4s;
}

.nav.scrolled {
  background: rgba(255,253,248,0.95);
  backdrop-filter: blur(12px);
  box-shadow: 0 1px 0 var(--divider);
}

.nav.dark-hero { color: var(--cream); }
.nav.dark-hero .nav__logo-text { color: var(--cream); }
.nav.dark-hero .nav__link { color: rgba(255,255,255,0.85); }
.nav.dark-hero .nav__cta { border-color: rgba(255,255,255,0.5); color: var(--cream); }
.nav.dark-hero.scrolled { color: var(--ink); }
.nav.dark-hero.scrolled .nav__logo-text { color: var(--ocean); }
.nav.dark-hero.scrolled .nav__link { color: var(--ink); }
.nav.dark-hero.scrolled .nav__cta { border-color: var(--terra); color: var(--ocean); }

.nav__inner {
  width: 100%;
  max-width: 1180px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 2rem;
}

.nav__logo {
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
  flex-shrink: 0;
}

.nav__logo-eyebrow {
  font-size: 0.55rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--terra);
  font-weight: 500;
  line-height: 1;
}

.nav__logo-text {
  font-family: var(--font-serif);
  font-size: 1.3rem;
  font-weight: 400;
  color: var(--ocean);
  line-height: 1;
  letter-spacing: 0.02em;
}

.nav__links {
  display: flex;
  align-items: center;
  gap: 2rem;
  list-style: none;
}

.nav__link {
  font-size: 0.8rem;
  font-weight: 400;
  letter-spacing: 0.04em;
  color: var(--ink);
  position: relative;
  transition: color 0.2s;
}

.nav__link::after {
  content: '';
  position: absolute;
  bottom: -2px; left: 0;
  width: 0; height: 1px;
  background: var(--terra);
  transition: width 0.3s ease;
}

.nav__link:hover::after,
.nav__link.active::after { width: 100%; }

.nav__cta {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.8rem;
  font-weight: 500;
  color: var(--ocean);
  border: 1px solid var(--terra);
  padding: 0.55rem 1.1rem;
  border-radius: 100px;
  transition: background 0.2s, color 0.2s;
  white-space: nowrap;
}

.nav__cta:hover { background: var(--terra); color: var(--cream); }

.nav__hamburger {
  display: none;
  flex-direction: column;
  gap: 5px;
  width: 28px;
  cursor: pointer;
}

.nav__hamburger span {
  display: block;
  height: 1.5px;
  background: currentColor;
  border-radius: 2px;
  transition: transform 0.3s, opacity 0.3s;
}

/* ── MOBILE NAV ── */
.nav__mobile {
  display: none;
  position: fixed;
  inset: 0;
  background: var(--ocean);
  z-index: 999;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2rem;
}

.nav__mobile.open { display: flex; }

.nav__mobile a {
  font-family: var(--font-serif);
  font-size: 2.5rem;
  color: var(--cream);
  letter-spacing: -0.01em;
  transition: color 0.2s;
}

.nav__mobile a:hover { color: var(--terra); }

.nav__mobile-cta {
  margin-top: 1rem;
  font-family: var(--font-sans) !important;
  font-size: 1rem !important;
  border: 1px solid var(--terra) !important;
  padding: 0.75rem 2rem;
  border-radius: 100px;
}

/* ── HERO ── */
.hero {
  position: relative;
  min-height: 100vh;
  display: flex;
  align-items: flex-end;
  padding-bottom: 6rem;
  overflow: hidden;
}

.hero__bg {
  position: absolute;
  inset: 0;
  background: var(--ocean);
}

.hero__bg img,
.hero__bg video {
  position: absolute;
  inset: 0;
  width: 100%; height: 100%;
  object-fit: cover;
  z-index: 0;
}

.hero__bg::after {
  content: '';
  position: absolute;
  inset: 0;
  z-index: 1;
  background: linear-gradient(to bottom, rgba(27,61,79,0.2) 0%, rgba(27,61,79,0.7) 100%);
}

.hero__placeholder {
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, #1B3D4F 0%, #0d2030 60%, #1a2e25 100%);
  display: flex;
  align-items: center;
  justify-content: center;
}

.hero__placeholder-label {
  font-size: 0.7rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.3);
  border: 1px dashed rgba(255,255,255,0.2);
  padding: 0.5rem 1rem;
  border-radius: 6px;
}

.hero__content {
  position: relative;
  z-index: 1;
  color: var(--cream);
  max-width: 1000px;
}

.hero__eyebrow {
  font-size: 0.65rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--terra);
  font-weight: 500;
  margin-bottom: 1.25rem;
  display: block;
}

.hero__title {
  font-family: var(--font-serif);
  font-size: clamp(3rem, 7vw, 5.5rem);
  font-weight: 400;
  line-height: 1.05;
  letter-spacing: -0.02em;
  color: var(--cream);
  margin-bottom: 1.5rem;
}

.hero__title em { color: var(--terra); font-style: italic; }

.hero__subtitle {
  font-size: 1rem;
  color: rgba(255,255,255,0.75);
  max-width: 520px;
  line-height: 1.7;
  margin-bottom: 2.5rem;
}

.hero__actions { display: flex; align-items: center; gap: 1rem; flex-wrap: wrap; }

/* ── BUTTONS ── */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  font-size: 0.85rem;
  font-weight: 500;
  padding: 0.85rem 1.8rem;
  border-radius: 100px;
  transition: all 0.25s ease;
  white-space: nowrap;
  letter-spacing: 0.02em;
}

.btn-primary {
  background: var(--terra);
  color: var(--cream);
}

.btn-primary:hover {
  background: #b56c31;
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(200,121,65,0.35);
}

.btn-outline {
  border: 1px solid rgba(255,255,255,0.5);
  color: var(--cream);
}

.btn-outline:hover {
  background: rgba(255,255,255,0.1);
  border-color: rgba(255,255,255,0.8);
}

.btn-outline-dark {
  border: 1px solid var(--divider);
  color: var(--ocean);
}

.btn-outline-dark:hover {
  background: var(--ocean);
  color: var(--cream);
  border-color: var(--ocean);
}

.btn-wa {
  background: #25D366;
  color: white;
}

.btn-wa:hover {
  background: #1ebe5a;
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(37,211,102,0.35);
}

/* ── STATS BAR ── */
.stats-bar {
  background: var(--ocean);
  padding: 0;
  display: flex;
  overflow: hidden;
  position: relative;
}

.stats-bar::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 2px;
  background: linear-gradient(to right, transparent, var(--terra) 25%, var(--terra) 75%, transparent);
}

.stats-bar__inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  width: 100%;
  max-width: 1180px;
  margin: 0 auto;
  padding: 0 2rem;
}

.stats-bar__item {
  padding: 3.5rem 1.5rem;
  text-align: center;
  flex: 1;
}

.stats-bar__num {
  font-family: var(--font-serif);
  font-size: clamp(3rem, 5vw, 4.5rem);
  color: var(--cream);
  line-height: 1;
  letter-spacing: -0.02em;
  display: block;
  margin-bottom: 0.4rem;
}

.stats-bar__num em { color: var(--terra); font-style: normal; }

.stats-bar__label {
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.45);
  font-weight: 500;
}

/* ── POOL VIDEO SECTION ── */
.pool-video-section {
  position: relative;
  height: 70vh;
  min-height: 480px;
  overflow: hidden;
  background: #0d1f2a;
  display: flex;
  align-items: center;
  justify-content: center;
}

.pool-video-section__media {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  will-change: transform;
}

/* Video placeholder — shown until client drops in their video */
.pool-video-section__placeholder {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 1rem;
  background: linear-gradient(160deg, #0d1f2a 0%, #1B3D4F 50%, #142d1e 100%);
}

.pool-video-section__placeholder-icon {
  width: 64px; height: 64px;
  border: 2px dashed rgba(255,255,255,0.25);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
}

.pool-video-section__placeholder-text {
  font-size: 0.7rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.35);
  text-align: center;
}

.pool-video-section__overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom, rgba(27,61,79,0.1) 0%, rgba(27,61,79,0.6) 100%);
  z-index: 1;
}

.pool-video-section__caption {
  position: relative;
  z-index: 2;
  text-align: center;
  color: var(--cream);
}

.pool-video-section__caption h2 {
  font-family: var(--font-serif);
  font-size: clamp(2rem, 5vw, 3.5rem);
  color: var(--cream);
  margin-bottom: 0.75rem;
}

.pool-video-section__caption p {
  font-size: 0.95rem;
  color: rgba(255,255,255,0.7);
}

/* ── VILLA GRID ── */
.villas-grid__filter {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 2.5rem;
  flex-wrap: wrap;
}

.filter-btn {
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 0.5rem 1.1rem;
  border-radius: 100px;
  border: 1px solid var(--divider);
  color: var(--muted);
  background: transparent;
  transition: all 0.2s;
}

.filter-btn:hover,
.filter-btn.active {
  background: var(--ocean);
  color: var(--cream);
  border-color: var(--ocean);
}

.villas-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
}

.villa-card {
  background: var(--cream);
  border-radius: var(--radius-lg);
  overflow: hidden;
  border: 1px solid var(--divider);
  transition: transform 0.3s, box-shadow 0.3s;
  display: flex;
  flex-direction: column;
}

.villa-card:hover {
  transform: translateY(-3px);
  box-shadow: inset 0 0 0 2px var(--terra), 0 16px 48px var(--shadow-lg);
}

.villa-card:hover .villa-card__name { color: var(--terra); }

.villa-card[data-hidden="true"] { display: none; }

.villa-card__img {
  aspect-ratio: 4/3;
  background: var(--ocean);
  position: relative;
  overflow: hidden;
}

.villa-card__img img {
  width: 100%; height: 100%;
  object-fit: cover;
  transition: transform 0.6s ease;
}

.villa-card:hover .villa-card__img img { transform: scale(1.04); }

.villa-card__badge {
  position: absolute;
  top: 1rem; left: 1rem;
  font-size: 0.6rem;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  padding: 0.3rem 0.75rem;
  border-radius: 100px;
  background: var(--terra);
  color: white;
}

.villa-card__img-placeholder {
  width: 100%; height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, var(--ocean) 0%, var(--tropical) 100%);
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.4);
}

.villa-card__body {
  padding: 1.5rem;
  flex: 1;
  display: flex;
  flex-direction: column;
}

.villa-card__location {
  font-size: 0.68rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--terra);
  font-weight: 500;
  margin-bottom: 0.5rem;
}

.villa-card__name {
  font-family: var(--font-serif);
  font-size: 1.45rem;
  line-height: 1.15;
  color: var(--ocean);
  margin-bottom: 0.6rem;
  transition: color 0.3s;
}

.villa-card__tagline {
  font-size: 0.83rem;
  color: var(--muted);
  line-height: 1.6;
  margin-bottom: 1.25rem;
  flex: 1;
}

.villa-card__features {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  margin-bottom: 1.25rem;
}

.feature-pill {
  font-size: 0.65rem;
  font-weight: 500;
  letter-spacing: 0.06em;
  padding: 0.25rem 0.65rem;
  border-radius: 100px;
  background: var(--sand);
  color: var(--ocean);
  border: 1px solid var(--divider);
}

.villa-card__footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 1rem;
  border-top: 1px solid var(--divider);
}

.villa-card__beds {
  font-size: 0.8rem;
  font-weight: 500;
  color: var(--ocean);
}

.villa-card__cta {
  font-size: 0.75rem;
  font-weight: 500;
  color: var(--terra);
  display: flex;
  align-items: center;
  gap: 0.3rem;
  transition: gap 0.2s;
}

.villa-card__cta:hover { gap: 0.5rem; }

/* ── STORY SECTION ── */
.story-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 5rem;
  align-items: center;
}

.story-grid.reverse { direction: rtl; }
.story-grid.reverse > * { direction: ltr; }

.story-img {
  aspect-ratio: 3/4;
  border-radius: var(--radius-lg);
  overflow: hidden;
  background: var(--ocean);
  position: relative;
}

.story-img img { width: 100%; height: 100%; object-fit: cover; }

.story-img__placeholder {
  width: 100%; height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(160deg, var(--ocean), var(--tropical));
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.35);
  text-align: center;
  padding: 2rem;
}

.story-content h2 { margin-bottom: 1.25rem; color: var(--ocean); }
.story-content p { margin-bottom: 1rem; }
.story-content .btn { margin-top: 1.5rem; }

/* ── EXPERIENCES ── */
.experiences-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
  margin-top: 3rem;
}

.exp-card {
  background: var(--cream);
  border: 1px solid var(--divider);
  border-radius: var(--radius);
  padding: 2rem 1.75rem;
  position: relative;
  overflow: hidden;
  transition: box-shadow 0.3s;
}

.exp-card:hover { box-shadow: 0 8px 32px var(--shadow); }

.exp-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0;
  width: 3px; height: 100%;
  background: var(--terra);
  border-radius: 3px 0 0 3px;
}

.exp-icon {
  font-size: 1.8rem;
  margin-bottom: 1rem;
  display: block;
  color: var(--terra);
}

.exp-card h3 {
  font-size: 1.25rem;
  color: var(--ocean);
  margin-bottom: 0.5rem;
}

.exp-card p { font-size: 0.85rem; }

/* ── PRIVACY SECTION ── */
.privacy-section {
  background: var(--ocean);
  padding: 6rem 0;
  text-align: center;
}

.privacy-section h2 { color: var(--cream); margin-bottom: 1.25rem; }
.privacy-section p { color: rgba(255,255,255,0.65); max-width: 580px; margin: 0 auto 0.75rem; }

.privacy-items {
  display: flex;
  justify-content: center;
  gap: 3rem;
  margin-top: 3rem;
  flex-wrap: wrap;
}

.privacy-item {
  text-align: center;
  color: var(--cream);
}

.privacy-item__icon {
  width: 56px; height: 56px;
  border: 1px solid rgba(255,255,255,0.2);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  margin: 0 auto 0.75rem;
  font-size: 1.4rem;
}

.privacy-item__label {
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  color: rgba(255,255,255,0.6);
}

/* ── SOCIAL PROOF ── */
.reviews-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
  margin-top: 3rem;
}

.review-card {
  background: var(--cream);
  border: 1px solid var(--divider);
  border-radius: var(--radius);
  padding: 1.75rem;
}

.review-stars {
  color: var(--terra);
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  margin-bottom: 0.75rem;
}

.review-card blockquote {
  font-family: var(--font-serif);
  font-size: 1.1rem;
  line-height: 1.6;
  color: var(--ocean);
  margin-bottom: 1rem;
}

.review-card cite {
  font-size: 0.75rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--muted);
  font-style: normal;
}

.tripadvisor-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.75rem;
  background: var(--cream);
  border: 1px solid var(--divider);
  border-radius: 100px;
  padding: 0.65rem 1.25rem;
  margin-top: 2.5rem;
  font-size: 0.8rem;
  font-weight: 500;
  color: var(--ocean);
  transition: box-shadow 0.2s;
}

.tripadvisor-badge:hover { box-shadow: 0 4px 16px var(--shadow); }

.tripadvisor-badge .ta-logo {
  font-size: 0.65rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: #00AF87;
  font-weight: 700;
}

/* ── CELEBRATIONS CTA ── */
.celebrations-cta {
  background: var(--sand);
  padding: 6rem 0;
}

.celebrations-cta__inner {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4rem;
  align-items: center;
}

.celebrations-cta__img {
  aspect-ratio: 16/9;
  border-radius: var(--radius-lg);
  overflow: hidden;
  background: var(--ocean);
}

.celebrations-cta__img img { width: 100%; height: 100%; object-fit: cover; }

.celebrations-cta__img-placeholder {
  width: 100%; height: 100%;
  display: flex; align-items: center; justify-content: center;
  background: linear-gradient(135deg, var(--terra), #8b4a1a);
  font-size: 0.65rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.4);
}

.celebrations-cta__content h2 { color: var(--ocean); margin-bottom: 1.25rem; }

/* ── WHATSAPP FLOAT ── */
.wa-float {
  position: fixed;
  bottom: 2rem; right: 2rem;
  z-index: 900;
  background: #25D366;
  color: white;
  width: 56px; height: 56px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.4rem;
  box-shadow: 0 4px 20px rgba(37,211,102,0.5);
  transition: transform 0.2s, box-shadow 0.2s;
}

.wa-float:hover {
  transform: scale(1.08);
  box-shadow: 0 6px 28px rgba(37,211,102,0.65);
}

/* ── FOOTER ── */
.footer {
  background: var(--ink);
  color: var(--cream);
  padding: 4rem 0 2.5rem;
}

.footer__grid {
  display: grid;
  grid-template-columns: 1.5fr 1fr 1fr 1.2fr;
  gap: 3rem;
  padding-bottom: 3rem;
  border-bottom: 1px solid rgba(255,255,255,0.1);
  margin-bottom: 2rem;
}

.footer__brand p {
  font-size: 0.85rem;
  color: rgba(255,255,255,0.55);
  line-height: 1.7;
  margin-top: 1rem;
  max-width: 280px;
}

.footer__logo {
  font-family: var(--font-serif);
  font-size: 1.5rem;
  color: var(--cream);
  letter-spacing: 0.02em;
}

.footer__logo span { color: var(--terra); }

.footer h4 {
  color: rgba(255,255,255,0.4);
  font-size: 0.6rem;
  letter-spacing: 0.18em;
  margin-bottom: 1.25rem;
}

.footer__links { list-style: none; display: flex; flex-direction: column; gap: 0.7rem; }

.footer__links a {
  font-size: 0.85rem;
  color: rgba(255,255,255,0.65);
  transition: color 0.2s;
}

.footer__links a:hover { color: var(--terra); }

.footer__contact p {
  font-size: 0.85rem;
  color: rgba(255,255,255,0.65);
  margin-bottom: 0.4rem;
}

.footer__contact a { color: var(--terra); }

.footer__bottom {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.72rem;
  color: rgba(255,255,255,0.3);
  letter-spacing: 0.04em;
  flex-wrap: wrap;
  gap: 0.5rem;
}

/* ── PAGE HERO (inner pages) ── */
.page-hero {
  padding: calc(var(--nav-h) + 4rem) 0 4rem;
  background: var(--ocean);
  color: var(--cream);
  text-align: center;
}

.page-hero h1 { color: var(--cream); margin-bottom: 0.75rem; }
.page-hero p { color: rgba(255,255,255,0.7); font-size: 1rem; max-width: 560px; margin: 0 auto; }

/* ── VILLA DETAIL PAGE ── */
.villa-detail__hero {
  position: relative;
  height: 70vh;
  min-height: 480px;
  overflow: hidden;
  display: flex;
  align-items: flex-end;
}

.villa-detail__hero-bg {
  position: absolute;
  inset: 0;
  background: var(--ocean);
}

.villa-detail__hero-bg img {
  width: 100%; height: 100%;
  object-fit: cover;
  opacity: 0.7;
}

.villa-detail__hero-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(27,61,79,0.9) 0%, rgba(27,61,79,0.1) 60%);
}

.villa-detail__hero-content {
  position: relative;
  z-index: 1;
  color: var(--cream);
  padding: 3rem 2rem;
  max-width: 1180px;
  margin: 0 auto;
  width: 100%;
}

.villa-detail__hero-content h1 { color: var(--cream); margin-bottom: 0.5rem; }

.villa-detail__badges {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin-bottom: 1rem;
}

.badge-pill {
  font-size: 0.65rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 0.3rem 0.8rem;
  border-radius: 100px;
  background: rgba(200,121,65,0.25);
  color: var(--terra);
  border: 1px solid rgba(200,121,65,0.4);
}

.villa-detail__content {
  display: grid;
  grid-template-columns: 1fr 340px;
  gap: 3rem;
  padding: 4rem 0;
}

.villa-detail__sidebar {
  position: sticky;
  top: calc(var(--nav-h) + 1.5rem);
  align-self: start;
}

.booking-widget {
  background: var(--cream);
  border: 1px solid var(--divider);
  border-radius: var(--radius-lg);
  padding: 2rem;
  box-shadow: 0 8px 32px var(--shadow);
}

.booking-widget h3 {
  font-size: 1.3rem;
  color: var(--ocean);
  margin-bottom: 0.25rem;
}

.booking-widget p { font-size: 0.82rem; margin-bottom: 1.5rem; }

.booking-widget .btn { width: 100%; justify-content: center; margin-bottom: 0.75rem; }

.booking-widget__note {
  font-size: 0.72rem;
  color: var(--muted);
  text-align: center;
}

.amenities-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 0.75rem;
  margin-top: 1.5rem;
}

.amenity-item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 0.85rem;
  color: var(--ink);
}

.amenity-item span:first-child { font-size: 1.1rem; }

/* Pool spec card */
.pool-spec {
  background: var(--sand);
  border-radius: var(--radius);
  padding: 1.5rem;
  margin-top: 2rem;
}

.pool-spec h4 { color: var(--ocean); margin-bottom: 0.75rem; }
.pool-spec p { font-size: 0.83rem; }

/* ── FORM ── */
.contact-form {
  background: var(--cream);
  border: 1px solid var(--divider);
  border-radius: var(--radius-lg);
  padding: 2.5rem;
}

.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1rem; }
.form-group { display: flex; flex-direction: column; gap: 0.4rem; margin-bottom: 1rem; }

.form-group label {
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--ocean);
}

.form-group input,
.form-group select,
.form-group textarea {
  font-family: var(--font-sans);
  font-size: 0.9rem;
  padding: 0.75rem 1rem;
  border: 1px solid var(--divider);
  border-radius: 8px;
  background: var(--cream);
  color: var(--ink);
  transition: border-color 0.2s;
  outline: none;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  border-color: var(--ocean);
}

.form-group textarea { resize: vertical; min-height: 120px; }

/* ── BREADCRUMB ── */
.breadcrumb {
  font-size: 0.75rem;
  color: rgba(255,255,255,0.5);
  display: flex;
  gap: 0.5rem;
  align-items: center;
  margin-bottom: 1rem;
}

.breadcrumb a { color: rgba(255,255,255,0.5); transition: color 0.2s; }
.breadcrumb a:hover { color: var(--terra); }
.breadcrumb span { color: rgba(255,255,255,0.25); }

/* ── DIVIDERS ── */
.divider-line { width: 48px; height: 2px; background: var(--terra); margin: 1.5rem 0; }
.divider-line.center { margin: 1.5rem auto; }

/* ── RESPONSIVE ── */
@media (max-width: 1024px) {
  .villas-grid { grid-template-columns: repeat(2, 1fr); }
  .footer__grid { grid-template-columns: 1fr 1fr; gap: 2rem; }
  .story-grid { gap: 3rem; }
}

@media (max-width: 768px) {
  section { padding: 4rem 0; }
  .container { padding: 0 1.25rem; }
  .container--narrow { padding: 0 1.25rem; }

  .nav__links { display: none; }
  .nav__cta.desktop { display: none; }
  .nav__hamburger { display: flex; }

  .hero { padding-bottom: 4rem; }
  .hero__title { font-size: clamp(2.4rem, 8vw, 3.5rem); }

  .stats-bar__inner { display: grid; grid-template-columns: repeat(2, 1fr); }
  .stats-bar__item:nth-child(2) { border-right: none; }

  .villas-grid { grid-template-columns: 1fr; }
  .experiences-grid { grid-template-columns: 1fr 1fr; }
  .reviews-grid { grid-template-columns: 1fr; }
  .story-grid { grid-template-columns: 1fr; gap: 2rem; }
  .story-grid.reverse { direction: ltr; }

  .celebrations-cta__inner { grid-template-columns: 1fr; gap: 2rem; }

  .villa-detail__content { grid-template-columns: 1fr; }
  .villa-detail__sidebar { position: static; }

  .footer__grid { grid-template-columns: 1fr; gap: 2rem; }
  .footer__bottom { flex-direction: column; text-align: center; }

  .privacy-items { gap: 2rem; }
  .form-row { grid-template-columns: 1fr; }
}

@media (max-width: 480px) {
  .experiences-grid { grid-template-columns: 1fr; }
  .stats-bar__num { font-size: 2.2rem; }
  .hero__actions { flex-direction: column; align-items: flex-start; }
}

/* ── PRINT ── */
@media print {
  .nav, .wa-float, .nav__mobile { display: none !important; }
  .hero { min-height: auto; }
  section { padding: 2rem 0; break-inside: avoid; }
}

/* ── SKIP LINK ── */
.skip-link {
  position: absolute;
  top: -100%;
  left: 1rem;
  z-index: 9999;
  padding: 0.75rem 1.5rem;
  background: var(--ocean);
  color: white;
  font-family: var(--font-sans);
  font-size: 0.9rem;
  font-weight: 500;
  border-radius: var(--radius);
  text-decoration: none;
  transition: top 0.15s ease;
}
.skip-link:focus { top: 1rem; }

/* ── FOCUS VISIBLE ── */
:focus-visible {
  outline: 3px solid var(--terra);
  outline-offset: 3px;
  border-radius: 2px;
}
:focus:not(:focus-visible) { outline: none; }

/* ── TOUCH & INTERACTION ── */
a, button, [role="button"], input, select, textarea, label[for] {
  touch-action: manipulation;
}

/* ── REDUCED MOTION ── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* ══════════════════════════════════════════
   TESTIMONIALS SCROLL WALL
   ══════════════════════════════════════════ */
.testimonials-section { padding: 6rem 0; background: var(--cream); overflow: hidden; }

.testimonials-columns {
  display: flex;
  justify-content: center;
  gap: 1.5rem;
  height: 740px;
  overflow: hidden;
  mask-image: linear-gradient(to bottom, transparent, black 10%, black 90%, transparent);
  -webkit-mask-image: linear-gradient(to bottom, transparent, black 10%, black 90%, transparent);
  margin-top: 3rem;
}

.testi-col { display: flex; flex-direction: column; width: 320px; flex-shrink: 0; }

.testi-track {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  animation: testiScroll var(--dur, 15s) linear infinite;
}

@keyframes testiScroll {
  0%   { transform: translateY(0); }
  100% { transform: translateY(-50%); }
}

.testi-card {
  background: white;
  border: 1px solid var(--divider);
  border-radius: 24px;
  padding: 1.75rem;
  box-shadow: 0 4px 20px var(--shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  cursor: default;
}

.testi-card:hover {
  transform: translateY(-6px) scale(1.02);
  box-shadow: 0 20px 40px var(--shadow-lg);
}

.testi-stars { color: var(--terra); font-size: 0.8rem; letter-spacing: 0.15em; margin-bottom: 0.75rem; }

.testi-card blockquote {
  font-family: var(--font-serif);
  font-size: 1rem;
  line-height: 1.7;
  color: var(--ink);
  margin: 0 0 1.25rem;
  font-style: italic;
}

.testi-footer { display: flex; align-items: center; gap: 0.75rem; }

.testi-avatar {
  width: 42px; height: 42px;
  border-radius: 50%;
  object-fit: cover;
  border: 2px solid var(--divider);
  flex-shrink: 0;
}

.testi-footer cite {
  display: block;
  font-family: var(--font-sans);
  font-style: normal;
  font-weight: 600;
  font-size: 0.8rem;
  color: var(--ink);
  line-height: 1.3;
}

.testi-footer span {
  font-size: 0.75rem;
  color: var(--muted);
  display: block;
}

/* Col visibility */
.testi-col--2 { display: none; }
.testi-col--3 { display: none; }
@media (min-width: 720px)  { .testi-col--2 { display: flex; } }
@media (min-width: 1080px) { .testi-col--3 { display: flex; } }

/* ══════════════════════════════════════════
   EXPAND MAP WIDGET
   ══════════════════════════════════════════ */
.expand-map-wrap {
  perspective: 1000px;
  cursor: pointer;
  user-select: none;
  display: inline-block;
  position: relative;
  margin-bottom: 1.5rem;
}

.expand-map {
  position: relative;
  overflow: hidden;
  border-radius: 20px;
  background: var(--ocean);
  border: 1px solid rgba(255,255,255,0.12);
  width: 260px;
  height: 152px;
  transform-style: preserve-3d;
  transition:
    width 0.45s cubic-bezier(0.4,0,0.2,1),
    height 0.45s cubic-bezier(0.4,0,0.2,1),
    transform 0.15s ease;
}

.expand-map.is-expanded { width: 380px; height: 290px; }

/* Grid (collapsed only) */
.expand-map__grid { position: absolute; inset: 0; opacity: 0.05; transition: opacity 0.3s; pointer-events: none; }
.expand-map.is-expanded .expand-map__grid { opacity: 0; }

/* Roads SVG layer */
.expand-map__roads { position: absolute; inset: 0; opacity: 0; transition: opacity 0.4s ease 0.1s; pointer-events: none; }
.expand-map.is-expanded .expand-map__roads { opacity: 1; }

/* Buildings */
.expand-map__buildings { position: absolute; inset: 0; pointer-events: none; }

.expand-map__building {
  position: absolute;
  border-radius: 3px;
  background: rgba(255,255,255,0.22);
  border: 1px solid rgba(255,255,255,0.12);
  opacity: 0;
  transform: scale(0.85);
  transition: opacity 0.4s ease, transform 0.4s ease;
}

.expand-map.is-expanded .expand-map__building { opacity: 1; transform: scale(1); }

/* Ocean/water block */
.expand-map__water {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  height: 30%;
  background: linear-gradient(to top, rgba(61,122,99,0.35), transparent);
  opacity: 0;
  transition: opacity 0.5s ease 0.2s;
  pointer-events: none;
}
.expand-map.is-expanded .expand-map__water { opacity: 1; }

/* Pin */
.expand-map__pin {
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -80%);
  opacity: 0;
  transition: opacity 0.4s ease 0.5s, transform 0.4s ease 0.5s;
  pointer-events: none;
}
.expand-map.is-expanded .expand-map__pin {
  opacity: 1;
  transform: translate(-50%, -100%);
}

/* Gradient overlay */
.expand-map__overlay {
  position: absolute; inset: 0; z-index: 2; pointer-events: none;
  background: linear-gradient(to top, rgba(27,61,79,0.65) 0%, transparent 55%);
}

/* Content */
.expand-map__content {
  position: relative; z-index: 3;
  height: 100%;
  display: flex; flex-direction: column; justify-content: space-between;
  padding: 1.1rem 1.25rem;
}

.expand-map__badge {
  display: flex; align-items: center; gap: 0.45rem;
  font-size: 0.62rem; font-weight: 600;
  letter-spacing: 0.14em; text-transform: uppercase;
  color: rgba(255,255,255,0.9);
  background: rgba(255,255,255,0.1);
  backdrop-filter: blur(8px);
  border-radius: 100px;
  padding: 0.3rem 0.65rem;
  width: fit-content;
}

.expand-map__badge-dot {
  width: 5px; height: 5px; border-radius: 50%;
  background: #34D399;
  animation: mapBlink 2s ease infinite;
}

@keyframes mapBlink { 0%,100%{opacity:1} 50%{opacity:0.35} }

.expand-map__location {
  font-family: var(--font-serif);
  font-size: 1.05rem;
  color: white;
  transition: transform 0.3s ease;
}

.expand-map-wrap:hover .expand-map__location { transform: translateX(3px); }

.expand-map__coords {
  font-family: var(--font-sans);
  font-size: 0.68rem;
  color: rgba(255,255,255,0.55);
  letter-spacing: 0.04em;
  overflow: hidden;
  max-height: 0;
  transition: max-height 0.3s ease 0.2s;
  margin-top: 0.2rem;
}

.expand-map.is-expanded .expand-map__coords { max-height: 2rem; }

.expand-map__underline {
  height: 1px;
  background: linear-gradient(to right, rgba(200,121,65,0.7), rgba(200,121,65,0.2), transparent);
  transform: scaleX(0.25);
  transform-origin: left;
  transition: transform 0.4s ease;
  margin-top: 0.5rem;
}

.expand-map-wrap:hover .expand-map__underline,
.expand-map.is-expanded .expand-map__underline { transform: scaleX(1); }

.expand-map__hint {
  position: absolute;
  bottom: -1.6rem; left: 50%;
  transform: translateX(-50%);
  font-size: 0.62rem;
  color: var(--muted);
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s ease;
}
.expand-map-wrap:hover:not(.map-expanded) .expand-map__hint { opacity: 1; }

/* ══════════════════════════════════════════
   EDITORIAL ENHANCEMENTS
   ══════════════════════════════════════════ */

/* 1. Hero staircase lines */
.hero__title-line { display: block; }
.hero__title-line--offset { margin-left: clamp(2.5rem, 14vw, 11rem); }

/* 2. Story pull quote */
.story-pullquote {
  margin: 4.5rem auto;
  text-align: center;
  max-width: 760px;
}

.story-pullquote__text {
  font-family: var(--font-serif);
  font-size: clamp(1.8rem, 3.5vw, 3rem);
  font-style: italic;
  color: var(--terra);
  font-weight: 300;
  letter-spacing: -0.015em;
  line-height: 1.25;
}

/* 3. Manifesto section */
.manifesto-section {
  background: var(--ocean);
  padding: 7rem 0;
}

.manifesto-section__inner { max-width: 1180px; margin: 0 auto; padding: 0 2rem; }

.manifesto-section__text {
  font-family: var(--font-serif);
  font-size: clamp(2.2rem, 5vw, 4.5rem);
  font-weight: 300;
  line-height: 1.15;
  color: var(--cream);
  letter-spacing: -0.02em;
  max-width: 900px;
}

.manifesto-section__text em { color: var(--terra); font-style: italic; }

/* 4. Featured villa card (flagship spans 2 columns) */
.villa-card--featured { grid-column: span 2; }
.villa-card--featured .villa-card__img { aspect-ratio: 16/7; }

/* 5. Asymmetric divider rule */
.divider-rule {
  height: 1px;
  background: var(--divider);
  margin: 3rem 0;
  position: relative;
}

.divider-rule::after {
  content: '';
  position: absolute;
  top: -1px; right: -2.5rem;
  width: 3.5rem; height: 3px;
  background: var(--terra);
  border-radius: 2px;
}

/* 6. Mobile nav subtitles */
.nav__mobile-sub {
  font-family: var(--font-sans);
  font-size: 0.55rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.28);
  display: block;
  margin-top: 0.2rem;
  font-style: normal;
}

/* 7. Mobile experiences horizontal scroll */
@media (max-width: 719px) {
  .experiences-grid {
    grid-template-columns: 268px;
    grid-auto-columns: 268px;
    grid-auto-flow: column;
    overflow-x: auto;
    scroll-snap-type: x mandatory;
    -webkit-overflow-scrolling: touch;
    padding-bottom: 1rem;
    margin-left: -2rem;
    margin-right: -2rem;
    padding-left: 2rem;
    padding-right: 2rem;
  }
  .exp-card { scroll-snap-align: start; }
}

/* ── ROOM GALLERY (Component5 — Capsule Slider) ── */
.room-gallery {
  padding: 4rem 0 5rem;
  background: var(--sand);
}

.room-gallery__header {
  margin-bottom: 2rem;
}

.room-gallery__tabs {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin-bottom: 2rem;
}

.room-gallery__tab {
  padding: 0.45rem 1.4rem;
  border-radius: 50px;
  border: 1.5px solid var(--ocean);
  background: transparent;
  color: var(--ocean);
  cursor: pointer;
  font-family: var(--font-sans);
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  transition: background 0.2s, color 0.2s;
}

.room-gallery__tab:hover,
.room-gallery__tab.active {
  background: var(--ocean);
  color: white;
}

.room-gallery__panels { position: relative; }

.room-gallery__panel { display: none; }

.room-gallery__panel.active {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  animation: panelFadeUp 0.35s ease;
}

.room-gallery__panel img {
  width: 100%;
  aspect-ratio: 4/3;
  object-fit: cover;
  border-radius: var(--radius-lg);
}

@keyframes panelFadeUp {
  from { opacity: 0; transform: translateY(14px); }
  to   { opacity: 1; transform: none; }
}

